const s=(e,n)=>{let t=e.amount;if(e.deductions){const u=(e.deductions.afp||0)+(e.deductions.sfs||0)+(e.deductions.isr||0)+(e.deductions.others?.reduce((a,c)=>a+c.amount,0)||0);t=Math.max(0,t-u)}let r=t;switch(n&&e.currency&&(e.currency==="USD"?r=t*n.usd.rate:e.currency==="EUR"&&(r=t*n.eur.rate)),e.frequency){case"Mensual":return r*12;case"Trimestral":return r*4;case"Anual":return r;case"Fijo":return r*12;case"Variable":return r*12;default:return r}},o=(e,n)=>e.reduce((t,r)=>t+s(r,n),0),l=(e,n="DOP")=>new Intl.NumberFormat("es-DO",{style:"currency",currency:n}).format(e),d=e=>new Intl.NumberFormat("en-US",{style:"currency",currency:"USD"}).format(e);export{o as a,d as b,s as c,l as f};
